#include <stdio.h>
#include <string.h>

int countSpecialNumbers(int L, int R, int K) {
    int count = 0;
    for (int i = L; i <= R; i++) {
        int num = i;
        int digits[10] = {0};
        while (num > 0) {
            digits[num % 10] = 1;
            num /= 10;
        }
        int divCount = 0;
        for (int j = 1; j <= 9; j++) {
            if (digits[j] == 1 && i % j == 0) {
                divCount++;
            }
        }
        if (divCount >= K) {
            count++;
        }
    }
    return count;
}

int main() {
    int Q;
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        int L, R, K;
        scanf("%d %d %d", &L, &R, &K);
        printf("%d\n", countSpecialNumbers(L, R, K));
    }
    return 0;
}

